#include <upc.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>

typedef struct { uint64_t code; char left; char right; int next; } Node;

shared int g_k;
shared Node *node_ptrs[THREADS];
shared int node_counts[THREADS];
shared int nbuckets_per_thread[THREADS];
shared int *bucket_heads_ptrs[THREADS];

static inline int base2bits(char c){ switch(c){ case 'A': return 0; case 'C': return 1; case 'G': return 2; case 'T': return 3; default: return 0; } }
static inline char bits2base(int b){ static const char map[4]={'A','C','G','T'}; return map[b&3]; }
static uint64_t encode_kmer(const char *s, int k){ uint64_t x=0; for(int i=0;i<k;i++){ x = (x<<2) | (uint64_t)base2bits(s[i]); } return x; }
static void decode_kmer(uint64_t code, int k, char *out){ for(int i=k-1;i>=0;i--){ out[i] = bits2base((int)(code & 3ULL)); code >>= 2; } out[k]='\0'; }
static inline uint64_t next_code(uint64_t code, int k, char add){ uint64_t mask = (k>=32)?~0ULL:((1ULL<<(2*(unsigned)k))-1ULL);
  uint64_t dropmask = (k>=32)?(~0ULL):((1ULL<<(2*((unsigned)k-1)))-1ULL);
  code &= mask; code = ((code & dropmask) << 2) | (uint64_t)base2bits(add); return code; }
static unsigned long long hash64(uint64_t x){ x ^= x >> 33; x *= 0xff51afd7ed558ccdULL; x ^= x >> 33; x *= 0xc4ceb9fe1a85ec53ULL; x ^= x >> 33; return (unsigned long long)x; }

static Node Node_lookup(uint64_t code){
  unsigned long long hv = hash64(code);
  int owner = (int)(hv % (unsigned long long)THREADS);
  int nb = nbuckets_per_thread[owner];
  shared int *heads = bucket_heads_ptrs[owner];
  int b = (int)(hv % (unsigned long long)nb);
  int cur = heads[b];
  while(cur != -1){
    Node n = node_ptrs[owner][cur];
    if(n.code == code) return n;
    cur = n.next;
  }
  Node empty; empty.code=0; empty.left='F'; empty.right='F'; empty.next=-1; return empty;
}

