    int b = (int)(hv % (unsigned long long)nbuckets);
    int old_head = bucket_heads_ptrs[MYTHREAD][b];
    node_ptrs[MYTHREAD][i].next = old_head;
    bucket_heads_ptrs[MYTHREAD][b] = i;
