typedef struct { uint64_t code; char left; char right; int next; } Node;

shared int g_k;
shared Node *node_ptrs[THREADS];
shared int node_counts[THREADS];
shared int nbuckets_per_thread[THREADS];
shared int *bucket_heads_ptrs[THREADS];

static inline int base2bits(char c){ switch(c){ case 'A': return 0; case 'C': return 1; case 'G': return 2; case 'T': return 3; default: return 0; } }
static inline char bits2base(int b){ static const char map[4]={'A','C','G','T'}; return map[b&3]; }
static uint64_t encode_kmer(const char *s, int k){ uint64_t x=0; for(int i=0;i<k;i++){ x = (x<<2) | (uint64_t)base2bits(s[i]); } return x; }
static void decode_kmer(uint64_t code, int k, char *out){ for(int i=k-1;i>=0;i--){ out[i] = bits2base((int)(code & 3ULL)); code >>= 2; } out[k]='\0'; }
static inline uint64_t next_code(uint64_t code, int k, char add){ uint64_t mask = (k>=32)?~0ULL:((1ULL<<(2*(unsigned)k))-1ULL);
  uint64_t dropmask = (k>=32)?(~0ULL):((1ULL<<(2*((unsigned)k-1)))-1ULL);
  code &= mask; code = ((code & dropmask) << 2) | (uint64_t)base2bits(add); return code; }
static unsigned long long hash64(uint64_t x){ x ^= x >> 33; x *= 0xff51afd7ed558ccdULL; x ^= x >> 33; x *= 0xc4ceb9fe1a85ec53ULL; x ^= x >> 33; return (unsigned long long)x; }

static Node Node_lookup(uint64_t code){
  unsigned long long hv = hash64(code);
  int owner = (int)(hv % (unsigned long long)THREADS);
  int nb = nbuckets_per_thread[owner];
  shared int *heads = bucket_heads_ptrs[owner];
  int b = (int)(hv % (unsigned long long)nb);
  int cur = heads[b];
  while(cur != -1){
    Node n = node_ptrs[owner][cur];
    if(n.code == code) return n;
    cur = n.next;
  }
  Node empty; empty.code=0; empty.left='F'; empty.right='F'; empty.next=-1; return empty;
}

int main(int argc, char **argv){
  if(MYTHREAD==0){ if(argc<2){ fprintf(stderr, "Usage: %s <input>\n", argv[0]); } }
  upc_barrier;
  const char *infile = (argc>=2? argv[1] : "test");
  if(MYTHREAD==0){ FILE *in=fopen(infile, "r"); if(!in){ perror("fopen"); g_k=0; } else { char buf[4096]; if(fgets(buf,sizeof(buf),in)){ char *tab=strchr(buf,'\t'); if(!tab){ g_k=0; } else { *tab='\0'; g_k=(int)strlen(buf); } } else g_k=0; fclose(in);} }
  upc_barrier;
  int k = g_k; if(k==0){ if(MYTHREAD==0) fprintf(stderr, "Failed to determine k.\n"); return 1; }
  FILE *in = fopen(infile, "r"); if(!in){ if(MYTHREAD==0) perror("fopen"); return 1; }
  char buf[4096]; int mycount=0; while(fgets(buf,sizeof(buf),in)){
    char *tab=strchr(buf,'\t'); if(!tab) continue; *tab='\0';
    uint64_t code=encode_kmer(buf,k); unsigned long long hv=hash64(code); int owner=(int)(hv % (unsigned long long)THREADS);
    if(owner==MYTHREAD) mycount++;
  }
  fclose(in);
  node_counts[MYTHREAD]=mycount; upc_barrier;
  node_ptrs[MYTHREAD] = (shared Node*)upc_alloc((size_t)((mycount>0?mycount:1))*sizeof(Node));
  int nbuckets = 1; while(nbuckets < mycount*2) nbuckets <<= 1; if(nbuckets<16) nbuckets=16;
  nbuckets_per_thread[MYTHREAD]=nbuckets;
  bucket_heads_ptrs[MYTHREAD] = (shared int*)upc_alloc(nbuckets*sizeof(int));
  for(int i=0;i<nbuckets;i++){ bucket_heads_ptrs[MYTHREAD][i] = -1; }
  upc_barrier;
  in = fopen(infile, "r"); if(!in){ if(MYTHREAD==0) perror("fopen2"); return 1; }
  int idx=0; while(fgets(buf,sizeof(buf),in)){
    char *tab=strchr(buf,'\t'); if(!tab) continue; *tab='\0'; char *ext=tab+1; char l='F', r='F'; int len=(int)strlen(ext); if(len>=2){ l=ext[0]; r=ext[1]; }
    uint64_t code=encode_kmer(buf,k); unsigned long long hv=hash64(code); int owner=(int)(hv % (unsigned long long)THREADS);
    if(owner==MYTHREAD){ node_ptrs[MYTHREAD][idx].code=code; node_ptrs[MYTHREAD][idx].left=l; node_ptrs[MYTHREAD][idx].right=r; node_ptrs[MYTHREAD][idx].next=-1; idx++; }
  }
  fclose(in);
  for(int i=0;i<idx;i++){
    unsigned long long hv = hash64(node_ptrs[MYTHREAD][i].code);
    int b = (int)(hv % (unsigned long long)nbuckets);
    int old_head = bucket_heads_ptrs[MYTHREAD][b];
    node_ptrs[MYTHREAD][i].next = old_head;
    bucket_heads_ptrs[MYTHREAD][b] = i;
  }
  upc_barrier;
  char outname[128]; snprintf(outname, sizeof(outname), "/app/pgen_%d.out", MYTHREAD);
  FILE *out = fopen(outname, "w"); if(!out){ if(MYTHREAD==0) perror("open out"); return 1; }
  for(int i=0;i<idx;i++){
    Node node = node_ptrs[MYTHREAD][i]; if(node.left!='F') continue;
    size_t cap = (size_t)k + 8192; char *seq = (char*)malloc(cap);
    char *kmer_str=(char*)malloc((size_t)k+1); decode_kmer(node.code, k, kmer_str);
    size_t len2=(size_t)k; memcpy(seq, kmer_str, (size_t)k); free(kmer_str);
    uint64_t code=node.code; char right=node.right;
    while(right!='F'){
      if(len2+1>=cap){ cap*=2; seq=(char*)realloc(seq, cap); }
      seq[len2++] = right;
      code = next_code(code, k, right);
      Node next = Node_lookup(code);
      if(next.left=='F' && next.right=='F' && next.code==0) break;
      right = next.right;
    }
    seq[len2]='\0'; fprintf(out, "%s\n", seq); free(seq);
  }
  fclose(out);
  upc_barrier; return 0;
}
