#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>

#ifndef THREADS
#define THREADS 4
#endif

typedef struct Node { uint64_t code; char left; char right; int next; } Node;

typedef struct { int *head; Node *nodes; int nbuckets; int nused; int cap; int k; } Hash;

static inline int base2bits(char c){ switch(c){ case 'A': return 0; case 'C': return 1; case 'G': return 2; case 'T': return 3; default: return 0; } }
static inline char bits2base(int b){ static const char map[4]={'A','C','G','T'}; return map[b&3]; }
static uint64_t encode_kmer(const char *s, int k){ uint64_t x=0; for(int i=0;i<k;i++){ x = (x<<2) | (uint64_t)base2bits(s[i]); } return x; }
static void decode_kmer(uint64_t code, int k, char *out){ for(int i=k-1;i>=0;i--){ out[i] = bits2base((int)(code & 3ULL)); code >>= 2; } out[k]='\0'; }
static inline uint64_t next_code(uint64_t code, int k, char add){ uint64_t mask = (k>=32)?~0ULL:((1ULL<<(2*(unsigned)k))-1ULL);
  uint64_t dropmask = (k>=32)?(~0ULL):((1ULL<<(2*((unsigned)k-1)))-1ULL);
  code &= mask; code = ((code & dropmask) << 2) | (uint64_t)base2bits(add); return code; }
static unsigned long long hash64(uint64_t x){ x ^= x >> 33; x *= 0xff51afd7ed558ccdULL; x ^= x >> 33; x *= 0xc4ceb9fe1a85ec53ULL; x ^= x >> 33; return (unsigned long long)x; }

static void hash_init(Hash *h, int nb){ h->nbuckets=nb; h->head=(int*)malloc(nb*sizeof(int)); for(int i=0;i<nb;i++) h->head[i]=-1; h->cap=nb*2; h->nodes=(Node*)malloc(h->cap*sizeof(Node)); h->nused=0; h->k=0; }
static void hash_free(Hash *h){ free(h->head); free(h->nodes); }
static void hash_reserve(Hash *h){ if(h->nused < h->cap) return; h->cap *= 2; h->nodes=(Node*)realloc(h->nodes, h->cap*sizeof(Node)); }
static void hash_insert(Hash *h, uint64_t code, char left, char right){ unsigned long long hv = hash64(code); int b = (int)(hv % (unsigned long long)h->nbuckets); hash_reserve(h); int idx=h->nused++; h->nodes[idx].code=code; h->nodes[idx].left=left; h->nodes[idx].right=right; h->nodes[idx].next=h->head[b]; h->head[b]=idx; }
static Node* hash_find(Hash *h, uint64_t code){ unsigned long long hv = hash64(code); int b = (int)(hv % (unsigned long long)h->nbuckets); int i=h->head[b]; while(i!=-1){ if(h->nodes[i].code==code) return &h->nodes[i]; i=h->nodes[i].next; } return NULL; }

int main(int argc, char **argv){ if(argc<2){ fprintf(stderr, "Usage: %s <input>\n", argv[0]); return 1; }
  const char *infile=argv[1]; FILE *in=fopen(infile, "r"); if(!in){ perror("fopen"); return 1; }
  char buf[4096]; int lines=0; int k=0;
  if(fgets(buf,sizeof(buf),in)){
    char *tab=strchr(buf,'\t'); if(!tab){ fprintf(stderr, "Bad format in first line\n"); fclose(in); return 2; }
    *tab='\0'; k=(int)strlen(buf); lines=1; while(fgets(buf,sizeof(buf),in)) lines++;
  } else { fclose(in); for(int t=0;t<THREADS;t++){ char outname[64]; sprintf(outname, "/app/pgen_%d.out", t); FILE *out=fopen(outname,"w"); if(out) fclose(out);} return 0; }
  fclose(in);
  Hash h; int nb=1; while(nb<lines*2) nb<<=1; hash_init(&h, nb); h.k=k;
  in=fopen(infile, "r"); if(!in){ perror("fopen2"); return 1; }
  while(fgets(buf,sizeof(buf),in)){
    char *tab=strchr(buf,'\t'); if(!tab) continue; *tab='\0'; char *ext=tab+1; char l='F', r='F'; int len=(int)strlen(ext); if(len>=2){ l=ext[0]; r=ext[1]; }
    uint64_t code = encode_kmer(buf, k);
    hash_insert(&h, code, l, r);
  }
  fclose(in);
  FILE *outs[THREADS]; for(int t=0;t<THREADS;t++){ char outname[64]; sprintf(outname, "/app/pgen_%d.out", t); outs[t]=fopen(outname, "w"); if(!outs[t]){ perror("open pgen.out"); outs[t]=stdout; } }
  for(int i=0;i<h.nused;i++){
    Node *node=&h.nodes[i]; if(node->left!='F') continue;
    unsigned long long hv = hash64(node->code); int owner=(int)(hv % (unsigned long long)THREADS);
